* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
}

.container {
  background: white;
  border-radius: 16px;
  padding: 40px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
  text-align: center;
  max-width: 500px;
}

h1 {
  color: #333;
  margin-bottom: 30px;
  font-size: 2.5em;
}

.info {
  margin-bottom: 30px;
  min-height: 60px;
  display: flex;
  justify-content: center;
  align-items: center;
}

.status {
  font-size: 1.2em;
  color: #555;
}

.status strong {
  color: #667eea;
  font-weight: bold;
}

.winner {
  font-size: 1.3em;
  font-weight: bold;
  color: #27ae60;
  animation: slideDown 0.4s ease-out;
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.board {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-bottom: 30px;
  padding: 10px;
  background: #f5f5f5;
  border-radius: 8px;
}

.cell {
  aspect-ratio: 1;
  background: white;
  border: 2px solid #ddd;
  border-radius: 8px;
  font-size: 2.5em;
  font-weight: bold;
  cursor: pointer;
  display: flex;
  justify-content: center;
  align-items: center;
  transition: all 0.2s ease;
  color: #333;
}

.cell:hover:not(.disabled) {
  background: #f0f0f0;
  transform: scale(1.05);
  border-color: #667eea;
}

.cell.disabled {
  cursor: not-allowed;
}

.cell.x {
  color: #667eea;
}

.cell.o {
  color: #e74c3c;
}

.cell.winner {
  background: #f1c40f;
  color: #333;
  font-weight: bold;
}

.reset-btn {
  background: #667eea;
  color: white;
  border: none;
  padding: 12px 30px;
  font-size: 1.1em;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
  font-weight: bold;
}

.reset-btn:hover {
  background: #764ba2;
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(102, 126, 234, 0.4);
}

.reset-btn:active {
  transform: translateY(0);
}

// 게임 상태 관리
const gameState = {
  board: Array(9).fill(null),
  currentPlayer: 'X',
  gameActive: true,
};

// 승리 조건
const WINNING_COMBINATIONS = [
  [0, 1, 2],
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6],
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8],
  [2, 4, 6],
];

// DOM 요소 캐싱
const boardElement = document.getElementById('board');
const turnElement = document.getElementById('turn');
const winnerElement = document.getElementById('winner');
const winnerText = document.getElementById('winner-text');
const resetButton = document.getElementById('reset');

// 게임 초기화
function initGame() {
  gameState.board = Array(9).fill(null);
  gameState.currentPlayer = 'X';
  gameState.gameActive = true;

  // UI 초기화
  updateTurnDisplay();
  winnerElement.style.display = 'none';
  renderBoard();
}

// 보드 렌더링
function renderBoard() {
  const cells = document.querySelectorAll('.cell');
  cells.forEach((cell, index) => {
    const value = gameState.board[index];
    cell.textContent = value || '';
    cell.classList.remove('x', 'o', 'winner', 'disabled');

    if (value) {
      cell.classList.add(value.toLowerCase());
      cell.classList.add('disabled');
    } else if (gameState.gameActive) {
      cell.classList.remove('disabled');
    } else {
      cell.classList.add('disabled');
    }
  });
}

// 차례 표시 업데이트
function updateTurnDisplay() {
  const player = gameState.currentPlayer === 'X' ? 'X' : 'O';
  turnElement.innerHTML = `현재 차례: <strong>${player}</strong>`;
}

// 승자 판정
function checkWinner() {
  for (const combination of WINNING_COMBINATIONS) {
    const [a, b, c] = combination;
    if (
      gameState.board[a] &&
      gameState.board[a] === gameState.board[b] &&
      gameState.board[a] === gameState.board[c]
    ) {
      return { winner: gameState.board[a], combination };
    }
  }
  return null;
}

// 무승부 판정
function isBoardFull() {
  return gameState.board.every((cell) => cell !== null);
}

// 게임 끝 처리
function endGame(result) {
  gameState.gameActive = false;
  winnerElement.style.display = 'block';

  if (result.type === 'win') {
    winnerText.textContent = `${result.winner} 플레이어 승리!`;
    highlightWinningCells(result.combination);
  } else if (result.type === 'draw') {
    winnerText.textContent = '무승부입니다!';
  }
}

// 승리한 셀 강조
function highlightWinningCells(combination) {
  const cells = document.querySelectorAll('.cell');
  combination.forEach((index) => {
    cells[index].classList.add('winner');
  });
}

// 셀 클릭 핸들러
function handleCellClick(event) {
  const cell = event.target;
  if (!cell.classList.contains('cell')) return;

  const index = parseInt(cell.dataset.index);

  // 이미 선택된 셀이거나 게임이 끝났으면 무시
  if (gameState.board[index] !== null || !gameState.gameActive) {
    return;
  }

  // 보드 업데이트
  gameState.board = gameState.board.map((val, i) =>
    i === index ? gameState.currentPlayer : val
  );

  // 승자 확인
  const result = checkWinner();
  if (result) {
    endGame({ type: 'win', winner: result.winner, combination: result.combination });
    renderBoard();
    return;
  }

  // 무승부 확인
  if (isBoardFull()) {
    endGame({ type: 'draw' });
    renderBoard();
    return;
  }

  // 플레이어 변경
  gameState.currentPlayer = gameState.currentPlayer === 'X' ? 'O' : 'X';
  updateTurnDisplay();
  renderBoard();
}

// 리셋 버튼 클릭 핸들러
function handleReset() {
  initGame();
}

// 이벤트 리스너 등록
boardElement.addEventListener('click', handleCellClick);
resetButton.addEventListener('click', handleReset);

// 게임 시작
initGame();

