// ============================================
// 테스트 유틸리티
// ============================================

let passCount = 0;
let failCount = 0;

function assert(condition, message) {
  if (!condition) {
    console.error(`❌ FAIL: ${message}`);
    failCount++;
    return false;
  }
  console.log(`✓ PASS: ${message}`);
  passCount++;
  return true;
}

function assertEquals(actual, expected, message) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    console.error(`❌ FAIL: ${message}`);
    console.error(`   Expected: ${JSON.stringify(expected)}`);
    console.error(`   Got:      ${JSON.stringify(actual)}`);
    failCount++;
    return false;
  }
  console.log(`✓ PASS: ${message}`);
  passCount++;
  return true;
}

function describe(name) {
  console.log(`\n📋 ${name}`);
  console.log('─'.repeat(50));
}

function testSuite(name) {
  console.log(`\n${'═'.repeat(50)}`);
  console.log(`🧪 ${name}`);
  console.log('═'.repeat(50));
}

// ============================================
// 게임 로직 함수들
// ============================================

const WINNING_COMBINATIONS = [
  [0, 1, 2], // 행
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6], // 열
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8], // 대각선
  [2, 4, 6],
];

function checkWinner(board) {
  for (const combination of WINNING_COMBINATIONS) {
    const [a, b, c] = combination;
    if (board[a] && board[a] === board[b] && board[a] === board[c]) {
      return { winner: board[a], combination };
    }
  }
  return null;
}

function isBoardFull(board) {
  return board.every((cell) => cell !== null);
}

function makeMove(board, index, player) {
  if (board[index] !== null) {
    return null; // 이미 차있는 셀
  }
  return board.map((val, i) => (i === index ? player : val));
}

function switchPlayer(currentPlayer) {
  return currentPlayer === 'X' ? 'O' : 'X';
}

// ============================================
// 테스트 시작
// ============================================

testSuite('틱택토 게임 로직 테스트');

// ============================================
// 테스트 1: 행 승리 감지
// ============================================
describe('행(Row) 승리 감지');

{
  // 첫 번째 행: X 승리
  const board = ['X', 'X', 'X', null, null, null, null, null, null];
  const result = checkWinner(board);
  assert(result !== null, '첫 번째 행 승리 감지');
  assertEquals(result?.winner, 'X', '첫 번째 행 승자는 X');
  assertEquals(result?.combination, [0, 1, 2], '첫 번째 행 조합 확인');
}

{
  // 두 번째 행: O 승리
  const board = [null, null, null, 'O', 'O', 'O', null, null, null];
  const result = checkWinner(board);
  assert(result !== null, '두 번째 행 승리 감지');
  assertEquals(result?.winner, 'O', '두 번째 행 승자는 O');
}

{
  // 세 번째 행: X 승리
  const board = [null, null, null, null, null, null, 'X', 'X', 'X'];
  const result = checkWinner(board);
  assert(result !== null, '세 번째 행 승리 감지');
  assertEquals(result?.combination, [6, 7, 8], '세 번째 행 조합 확인');
}

// ============================================
// 테스트 2: 열 승리 감지
// ============================================
describe('열(Column) 승리 감지');

{
  // 첫 번째 열: X 승리
  const board = ['X', null, null, 'X', null, null, 'X', null, null];
  const result = checkWinner(board);
  assert(result !== null, '첫 번째 열 승리 감지');
  assertEquals(result?.combination, [0, 3, 6], '첫 번째 열 조합 확인');
}

{
  // 두 번째 열: O 승리
  const board = [null, 'O', null, null, 'O', null, null, 'O', null];
  const result = checkWinner(board);
  assert(result !== null, '두 번째 열 승리 감지');
  assertEquals(result?.combination, [1, 4, 7], '두 번째 열 조합 확인');
}

{
  // 세 번째 열: X 승리
  const board = [null, null, 'X', null, null, 'X', null, null, 'X'];
  const result = checkWinner(board);
  assert(result !== null, '세 번째 열 승리 감지');
  assertEquals(result?.combination, [2, 5, 8], '세 번째 열 조합 확인');
}

// ============================================
// 테스트 3: 대각선 승리 감지
// ============================================
describe('대각선(Diagonal) 승리 감지');

{
  // 좌상향 → 우하향 대각선: X 승리
  const board = ['X', null, null, null, 'X', null, null, null, 'X'];
  const result = checkWinner(board);
  assert(result !== null, '주 대각선(0-4-8) 승리 감지');
  assertEquals(result?.combination, [0, 4, 8], '주 대각선 조합 확인');
}

{
  // 우상향 → 좌하향 대각선: O 승리
  const board = [null, null, 'O', null, 'O', null, 'O', null, null];
  const result = checkWinner(board);
  assert(result !== null, '부 대각선(2-4-6) 승리 감지');
  assertEquals(result?.combination, [2, 4, 6], '부 대각선 조합 확인');
}

// ============================================
// 테스트 4: 승리 미감지 (진행 중인 게임)
// ============================================
describe('승리 미감지 (진행 중)');

{
  // 아직 미완성
  const board = ['X', 'X', null, 'O', null, null, null, null, null];
  const result = checkWinner(board);
  assert(result === null, '진행 중인 게임에서 승리 미감지');
}

{
  // 거의 완성되었지만 아직 미완성
  const board = ['X', 'X', 'O', 'X', 'O', null, 'O', 'X', 'X'];
  const result = checkWinner(board);
  assert(result === null, '혼합된 게임에서 승리 미감지');
}

// ============================================
// 테스트 5: 무승부 감지
// ============================================
describe('무승부(Draw) 감지');

{
  // 완전히 찼지만 승리자 없음
  const board = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', 'X'];
  assert(isBoardFull(board), '보드가 가득 찼는지 확인');
  assert(checkWinner(board) === null, '무승부: 승리자 없음');
}

{
  // 다른 무승부 패턴
  const board = ['X', 'X', 'O', 'O', 'O', 'X', 'X', 'X', 'O'];
  assert(isBoardFull(board), '보드가 완전히 찼는지 확인');
  const result = checkWinner(board);
  assert(result === null, '무승부 감지: 승리자 없음');
}

// ============================================
// 테스트 6: 빈 보드 (무승부 아님)
// ============================================
describe('빈 보드 확인');

{
  const board = Array(9).fill(null);
  assert(!isBoardFull(board), '초기 보드는 가득 차지 않음');
  assert(checkWinner(board) === null, '초기 보드에 승리자 없음');
}

// ============================================
// 테스트 7: 턴 전환
// ============================================
describe('턴(Turn) 전환');

{
  assert(switchPlayer('X') === 'O', 'X → O 전환');
  assert(switchPlayer('O') === 'X', 'O → X 전환');
  assert(switchPlayer('X') === 'O', '다시 X → O 전환');
}

// ============================================
// 테스트 8: 말 놓기 (Move)
// ============================================
describe('말 놓기(Move) 동작');

{
  const board = Array(9).fill(null);
  const newBoard = makeMove(board, 0, 'X');
  assert(newBoard !== null, '비어있는 셀에 말 놓기 성공');
  assertEquals(newBoard[0], 'X', '올바른 위치에 X 배치');
  assertEquals(newBoard[1], null, '다른 셀은 변경 안 됨');
}

{
  const board = ['X', null, null, null, null, null, null, null, null];
  const newBoard = makeMove(board, 0, 'O');
  assert(newBoard === null, '이미 찬 셀에 말 놓기 실패');
}

{
  // 불변성 확인
  const board = Array(9).fill(null);
  const newBoard = makeMove(board, 4, 'X');
  assertEquals(board[4], null, '원본 보드는 변경 안 됨 (불변성)');
  assertEquals(newBoard[4], 'X', '새 보드에만 말 배치');
}

// ============================================
// 테스트 9: 게임 플로우 (통합)
// ============================================
describe('게임 플로우 (통합 테스트)');

{
  // X가 이기는 게임 시뮬레이션
  let board = Array(9).fill(null);
  let player = 'X';

  // 턴 1: X가 중앙에 놓음
  board = makeMove(board, 4, player);
  player = switchPlayer(player);

  // 턴 2: O가 좌상향에 놓음
  board = makeMove(board, 0, player);
  player = switchPlayer(player);

  // 턴 3: X가 좌측 놓음
  board = makeMove(board, 3, player);
  player = switchPlayer(player);

  // 턴 4: O가 놓음
  board = makeMove(board, 1, player);
  player = switchPlayer(player);

  // 턴 5: X가 우측 놓음 (승리)
  board = makeMove(board, 5, player);
  const result = checkWinner(board);

  assert(result !== null, '게임 흐름: 승리 감지');
  assertEquals(result?.winner, 'X', '게임 흐름: X가 승리');
  assertEquals(result?.combination, [3, 4, 5], '게임 흐름: 올바른 조합 (중앙 행)');
}

// ============================================
// 테스트 결과 요약
// ============================================
console.log('\n' + '═'.repeat(50));
console.log('📊 테스트 결과 요약');
console.log('═'.repeat(50));
console.log(`✓ 통과: ${passCount}`);
console.log(`❌ 실패: ${failCount}`);
console.log(`📈 총합: ${passCount + failCount}`);

if (failCount === 0) {
  console.log('\n🎉 모든 테스트 통과!');
  process.exit(0);
} else {
  console.log(`\n⚠️  ${failCount}개의 테스트 실패`);
  process.exit(1);
}

