{
  // 아직 미완성
  const board = ['X', 'X', null, 'O', null, null, null, null, null];
  const result = checkWinner(board);
  assert(result === null, '진행 중인 게임에서 승리 미감지');
}

{
  // 거의 완성되었지만 아직 미완성
  const board = ['X', 'X', 'O', 'X', 'O', null, 'O', 'X', 'X'];
  const result = checkWinner(board);
  assert(result === null, '혼합된 게임에서 승리 미감지');
}

// ============================================
// 테스트 5: 무승부 감지
// ============================================
describe('무승부(Draw) 감지');

{
  // 완전히 찼지만 승리자 없음
  const board = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', 'X'];
  assert(isBoardFull(board), '보드가 가득 찼는지 확인');
  assert(checkWinner(board) === null, '무승부: 승리자 없음');
}

{
  // 다른 무승부 패턴
  const board = ['X', 'X', 'O', 'O', 'O', 'X', 'X', 'X', 'O'];
  assert(isBoardFull(board), '보드가 완전히 찼는지 확인');
  const result = checkWinner(board);
  assert(result === null, '무승부 감지: 승리자 없음');
}

// ============================================
