function initGame() {
  gameState.board = Array(9).fill(null);
  gameState.currentPlayer = 'X';
  gameState.gameActive = true;

  // UI 초기화
  updateTurnDisplay();
  winnerElement.style.display = 'none';
  renderBoard();
}

// 보드 렌더링
function renderBoard() {
  const cells = document.querySelectorAll('.cell');
  cells.forEach((cell, index) => {
    const value = gameState.board[index];
    cell.textContent = value || '';
    cell.classList.remove('x', 'o', 'winner', 'disabled');

    if (value) {
      cell.classList.add(value.toLowerCase());
      cell.classList.add('disabled');
    } else if (gameState.gameActive) {
      cell.classList.remove('disabled');
    } else {
      cell.classList.add('disabled');
    }
  });
}

// 차례 표시 업데이트
function updateTurnDisplay() {
  const player = gameState.currentPlayer === 'X' ? 'X' : 'O';
  turnElement.innerHTML = `현재 차례: <strong>${player}</strong>`;
}

// 승자 판정
function checkWinner() {
  for (const combination of WINNING_COMBINATIONS) {
    const [a, b, c] = combination;
    if (
      gameState.board[a] &&
      gameState.board[a] === gameState.board[b] &&
      gameState.board[a] === gameState.board[c]
    ) {
      return { winner: gameState.board[a], combination };
    }
  }
  return null;
}

// 무승부 판정
function isBoardFull() {
  return gameState.board.every((cell) => cell !== null);
}

// 게임 끝 처리
function endGame(result) {
  gameState.gameActive = false;
  winnerElement.style.display = 'block';

  if (result.type === 'win') {
    winnerText.textContent = `${result.winner} 플레이어 승리!`;
    highlightWinningCells(result.combination);
  } else if (result.type === 'draw') {
    winnerText.textContent = '무승부입니다!';
  }
}

// 승리한 셀 강조
function highlightWinningCells(combination) {
  const cells = document.querySelectorAll('.cell');
  combination.forEach((index) => {
    cells[index].classList.add('winner');
  });
}

// 셀 클릭 핸들러
function handleCellClick(event) {
  const cell = event.target;
  if (!cell.classList.contains('cell')) return;

  const index = parseInt(cell.dataset.index);

  // 이미 선택된 셀이거나 게임이 끝났으면 무시
  if (gameState.board[index] !== null || !gameState.gameActive) {
    return;
  }

  // 보드 업데이트
  gameState.board = gameState.board.map((val, i) =>
    i === index ? gameState.currentPlayer : val
  );

  // 승자 확인
  const result = checkWinner();
  if (result) {
    endGame({ type: 'win', winner: result.winner, combination: result.combination });
    renderBoard();
    return;
  }

  // 무승부 확인
  if (isBoardFull()) {
    endGame({ type: 'draw' });
    renderBoard();
    return;
  }

  // 플레이어 변경
  gameState.currentPlayer = gameState.currentPlayer === 'X' ? 'O' : 'X';
  updateTurnDisplay();
  renderBoard();
}

// 리셋 버튼 클릭 핸들러
function handleReset() {
  initGame();
}

// 이벤트 리스너 등록
boardElement.addEventListener('click', handleCellClick);
resetButton.addEventListener('click', handleReset);

// 게임 시작
initGame();
